function PartRenderer({ part }: { part: any }) {
  switch (part.type) {
    case 'text':
      return <MarkdownArtifact text={part.text} />;

    case 'reasoning':
      return <ReasoningBlock text={part.text} />;

    case 'file':
      return <FileArtifact part={part} />;

    case 'source-url':
      return <SourceLink part={part} />;

    default:
      return null;
  }
}

import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

export function MarkdownArtifact({ text }: { text: string }) {
  return (
    <div className="prose prose-neutral dark:prose-invert max-w-none">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>
        {text}
      </ReactMarkdown>
    </div>
  );
}

type CodeArtifact = {
  type: 'code-artifact';
  filename: string;
  language: 'ts' | 'tsx' | 'js' | 'html' | 'css' | 'md' | 'json';
  content: string;
  preview?: 'none' | 'html' | 'markdown';
};

type ChartArtifact = {
  type: 'chart-artifact';
  chartType: 'line' | 'bar' | 'area' | 'pie';
  title?: string;
  xKey: string;
  yKeys: string[];
  data: Array<Record<string, string | number>>;
};

function MessageParts({ message }: { message: any }) {
  return (
    <div className="space-y-3">
      {message.parts.map((part: any, index: number) => {
        if (part.type === 'text') {
          return <MarkdownArtifact key={index} text={part.text} />;
        }

        if (part.type === 'reasoning') {
          return <ReasoningBlock key={index} text={part.text} />;
        }

        if (part.type === 'file') {
          return <FileArtifactRenderer key={index} part={part} />;
        }

        if (part.type === 'data' && part.data?.type === 'code-artifact') {
          return <CodeArtifactCard key={index} artifact={part.data} />;
        }

        if (part.type === 'data' && part.data?.type === 'chart-artifact') {
          return <ChartArtifactCard key={index} artifact={part.data} />;
        }

        return null;
      })}
    </div>
  );
}
